INSERT INTO users (id, google_id, email, name, avatar_url, created_at, updated_at)
INSERT INTO problem_statements (id, question, description, domain, hypothesis_count, created_at, updated_at) VALUES
('ps-1', 'What makes a counterargument persuasive?', 'Exploring the linguistic, structural, and psychological factors that determine whether a counterargument successfully changes someone''s opinion in online discourse.', 'persuasion', 47, 1726358400, 1726358400),
('ps-2', 'What makes an image unforgettable?', 'Investigating the visual, compositional, and semantic properties that cause certain images to persist in human memory while others are quickly forgotten.', 'memorability', 23, 1726358400, 1726358400),
('ps-3', 'What drives opinion change in online debates?', 'Understanding which conversational strategies, timing factors, and social dynamics predict successful persuasion in threaded online discussions.', 'persuasion', 31, 1726358400, 1726358400),
('ps-4', 'How does visual context affect memorability?', 'Examining how the surrounding context, scene category, and object relationships within an image influence its memorability score.', 'memorability', 15, 1726358400, 1726358400);
INSERT INTO datasets (id, name, huggingface_url, task_description, data_column_names, target_column_name, description, domain, submitted_by, created_at, updated_at) VALUES
('ds-1', 'Reddit ChangeMyView', 'https://huggingface.co/datasets/changemyview/change_my_view', 'You are a research scientist generating content-based hypotheses about whether a counterargument successfully changes the original poster''s opinion in online debates. Analyze linguistic features, argumentation strategies, and persuasive elements that predict opinion change.', '["text","author","reply_text","delta_awarded","timestamp"]', 'delta_awarded', 'A dataset of Reddit ChangeMyView posts and replies, with labels indicating whether the reply received a delta (opinion change). Contains over 30,000 discussion threads.', 'persuasion', 'system', 1726358400, 1726358400),
('ds-2', 'LaMem', 'https://huggingface.co/datasets/jmhessel/lamem', 'You are a research scientist generating content-based hypotheses about what makes an image memorable. Analyze visual features, composition, color, semantic content, and perceptual properties that contribute to memorability.', '["image","memorability_score","category","objects"]', 'memorability_score', 'Large-scale image memorability dataset with human-annotated memorability scores for diverse images. Contains 60,000 images with crowdsourced memorability annotations.', 'memorability', 'system', 1726358400, 1726358400),
('ds-3', 'Twitter Persuasion Pairs', 'https://huggingface.co/datasets/webis/webis-persuasion-16', 'You are a research scientist studying persuasive communication in short-form social media. Analyze how brevity, emotional tone, and social proof affect persuasion effectiveness in tweets.', '["tweet_text","reply_text","likes","retweets","persuasion_score"]', 'persuasion_score', 'Paired tweets and replies with crowdsourced persuasion effectiveness ratings. Covers a range of topics and conversational styles.', 'persuasion', 'system', 1726358400, 1726358400),
('ds-4', 'Visual Attention & Memorability', 'https://huggingface.co/datasets/mit/visual-attention', 'You are a research scientist studying what captures and holds visual attention. Analyze image properties that predict where people look and what they remember from natural scenes.', '["image","fixation_map","scene_category","objects"]', 'memorability_score', 'Eye-tracking and memorability data for natural scene images. Includes fixation maps, scene categories, and object annotations.', 'memorability', 'system', 1726358400, 1726358400);
